accordion.source:
"use client"

import * as React from "react"
import { ChevronDownIcon, ChevronRight } from "lucide-react"
import { Accordion as AccordionPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Accordion({
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn("border-b last:border-b-0", className)}
      {...props}
    />
  )
}

function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "focus-visible:border-ring focus-visible:ring-ring/50 flex flex-1 items-start justify-start gap-4 rounded-md py-4 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:ring-[3px] disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-90",
          className
        )}
        {...props}
      >
        <ChevronRight className="text-muted-foreground pointer-events-none size-4 shrink-0 translate-y-0.5 transition-transform duration-200" />
        {children}
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down overflow-hidden text-sm"
      {...props}
    >
      <div className={cn("pt-0 pb-4", className)}>{children}</div>
    </AccordionPrimitive.Content>
  )
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }

application-shell-13.source:
"use client";

import {
  BadgeCheck,
  BarChart3,
  Bell,
  Briefcase,
  ChevronDown,
  ChevronsUpDown,
  ClipboardList,
  Clock3,
  FileText,
  Folder,
  Globe2,
  LayoutDashboard,
  LogOut,
  Menu,
  Search,
  Sparkles,
  Star,
  User,
  Users,
} from "lucide-react";
import type { ComponentType, SVGProps } from "react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { cn } from "@/lib/utils";

type NavItem = {
  label: string;
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  href: string;
  isActive?: boolean;
  children?: NavItem[];
};

type NavGroup = {
  title: string;
  items: NavItem[];
};

const data = {
  brand: {
    name: "Blake UI",
    logo: "/blake-logo-icon.svg",
    alt: "Blake UI",
  },
  user: {
    name: "Joh Doe",
    email: "joh@blakeui.com",
    avatar: "https://i.pravatar.cc/150?img=15",
  },
  organization: {
    name: "Acme Inc",
    logo: "/blake-logo-icon.svg",
  },
};

const navGroups: NavGroup[] = [
  {
    title: "Overview",
    items: [
      {
        label: "Dashboard",
        icon: LayoutDashboard,
        href: "#",
        isActive: true,
      },
      { label: "Tasks", icon: ClipboardList, href: "#" },
      { label: "Roadmap", icon: BarChart3, href: "#" },
    ],
  },
  {
    title: "Projects",
    items: [
      {
        label: "Active Projects",
        icon: Briefcase,
        href: "#",
        children: [
          { label: "Project Alpha", icon: FileText, href: "#" },
          { label: "Project Beta", icon: FileText, href: "#" },
          { label: "Project Gamma", icon: FileText, href: "#" },
        ],
      },
      {
        label: "Archived",
        icon: Folder,
        href: "#",
        children: [
          { label: "2024 Archive", icon: FileText, href: "#" },
          { label: "2023 Archive", icon: FileText, href: "#" },
        ],
      },
    ],
  },
  {
    title: "Team",
    items: [
      { label: "Members", icon: Users, href: "#" },
      { label: "Sprints", icon: Clock3, href: "#" },
      { label: "Approvals", icon: BadgeCheck, href: "#" },
      { label: "Reviews", icon: Star, href: "#" },
    ],
  },
  {
    title: "Workspace",
    items: [
      { label: "Integrations", icon: Globe2, href: "#" },
      { label: "Automations", icon: Sparkles, href: "#" },
    ],
  },
];

function getInitials(name: string) {
  return name
    .split(" ")
    .map((part) => part[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();
}

function OrganizationSwitcher() {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" className="gap-2 px-2">
          <span className="flex size-6 shrink-0 items-center justify-center overflow-hidden rounded-md border border-border bg-background p-0.5">
            <img
              src={data.organization.logo}
              alt=""
              width={16}
              height={16}
              className="size-full object-contain"
            />
          </span>
          <span className="truncate text-sm font-medium text-foreground">
            {data.organization.name}
          </span>
          <ChevronDown className="ml-auto size-4 text-muted-foreground" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-56">
        <DropdownMenuLabel>Organizations</DropdownMenuLabel>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <div className="flex items-center gap-2">
            <span className="flex size-6 items-center justify-center overflow-hidden rounded-md border border-border bg-background p-0.5">
              <img
                src={data.organization.logo}
                alt=""
                width={16}
                height={16}
                className="size-full object-contain"
              />
            </span>
            <span>{data.organization.name}</span>
          </div>
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem>Create organization</DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

const NavDropdown = ({ group }: { group: NavGroup }) => {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" className="gap-1">
          {group.title}
          <ChevronDown className="size-3" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="start" className="w-48">
        {group.items.map((item) => {
          const Icon = item.icon;
          return (
            <div key={item.label}>
              <DropdownMenuItem asChild>
                <a href={item.href} className="flex items-center gap-2">
                  <Icon className="size-4" />
                  {item.label}
                </a>
              </DropdownMenuItem>
              {item.children?.map((child) => {
                const ChildIcon = child.icon;
                return (
                  <DropdownMenuItem key={child.label} asChild className="pl-6">
                    <a href={child.href} className="flex items-center gap-2">
                      <ChildIcon className="size-4" />
                      {child.label}
                    </a>
                  </DropdownMenuItem>
                );
              })}
            </div>
          );
        })}
      </DropdownMenuContent>
    </DropdownMenu>
  );
};

function MobileNav() {
  return (
    <Sheet>
      <SheetTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          className="md:hidden"
          aria-label="Open menu"
        >
          <Menu className="size-5" />
        </Button>
      </SheetTrigger>
      <SheetContent side="left" className="w-72 p-0">
        <SheetHeader className="px-4 pt-4">
          <SheetTitle className="flex items-center gap-2">
            <div className="flex aspect-square size-8 items-center justify-center overflow-hidden rounded-md">
              <img
                src={data.brand.logo}
                alt={data.brand.alt}
                width={20}
                height={20}
                className="size-full max-h-8 max-w-8 object-contain"
              />
            </div>
            {data.brand.name}
          </SheetTitle>
        </SheetHeader>
        <ScrollArea className="min-h-0 flex-1">
          <nav className="flex flex-col gap-4 px-4 py-4">
            {navGroups.map((group) => (
              <div key={group.title}>
                <div className="mb-2 text-xs font-medium tracking-wider text-muted-foreground uppercase">
                  {group.title}
                </div>
                <div className="flex flex-col gap-1">
                  {group.items.map((item) => {
                    const Icon = item.icon;
                    return (
                      <div key={item.label}>
                        <a
                          href={item.href}
                          className={cn(
                            "flex items-center gap-2 rounded-md px-2 py-1.5 text-sm hover:bg-muted",
                            item.isActive && "bg-muted font-medium",
                          )}
                        >
                          <Icon className="size-4" />
                          {item.label}
                        </a>
                        {item.children?.map((child) => {
                          const ChildIcon = child.icon;
                          return (
                            <a
                              key={child.label}
                              href={child.href}
                              className="flex items-center gap-2 rounded-md py-1.5 pr-2 pl-8 text-sm hover:bg-muted"
                            >
                              <ChildIcon className="size-4" />
                              {child.label}
                            </a>
                          );
                        })}
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </nav>
        </ScrollArea>
      </SheetContent>
    </Sheet>
  );
}

function SearchField({ className }: { className?: string }) {
  return (
    <div className={cn("relative", className)}>
      <Search className="pointer-events-none absolute top-1/2 left-2.5 size-4 -translate-y-1/2 text-muted-foreground" />
      <Input
        type="search"
        placeholder="Search..."
        className="h-9 w-full pl-8"
        aria-label="Search"
      />
    </div>
  );
}

function NavUser() {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" className="gap-2 px-2">
          <Avatar className="size-8">
            <AvatarImage src={data.user.avatar} alt={data.user.name} />
            <AvatarFallback className="text-xs">
              {getInitials(data.user.name)}
            </AvatarFallback>
          </Avatar>
          <span className="hidden text-sm font-medium md:inline">
            {data.user.name}
          </span>
          <ChevronsUpDown className="hidden size-4 md:block" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-56">
        <DropdownMenuLabel className="font-normal">
          <div className="flex flex-col space-y-1">
            <p className="text-sm font-medium">{data.user.name}</p>
            <p className="text-xs text-muted-foreground">{data.user.email}</p>
          </div>
        </DropdownMenuLabel>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <User className="mr-2 size-4" />
          Account
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <LogOut className="mr-2 size-4" />
          Log out
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

interface ApplicationShell13Props {
  className?: string;
}

export function ApplicationShell13({ className }: ApplicationShell13Props) {
  return (
    <div className={cn("flex min-h-svh flex-col bg-muted/50", className)}>
      <header className="sticky top-0 z-40 w-full border-b border-border bg-background">
        <div className="mx-auto grid h-14 w-full grid-cols-[auto_minmax(0,1fr)_auto] items-center gap-3 px-4 lg:px-6">
          <div className="flex items-center gap-3">
            <MobileNav />
            <a href="#" className="flex items-center gap-2">
              <div className="flex aspect-square size-8 items-center justify-center overflow-hidden rounded-md">
                <img
                  src={data.brand.logo}
                  alt={data.brand.alt}
                  width={20}
                  height={20}
                  className="size-full max-h-8 max-w-8 object-contain"
                />
              </div>
              <span className="font-semibold">{data.brand.name}</span>
            </a>
          </div>
          <div className="hidden w-full justify-self-center md:block md:max-w-md">
            <SearchField />
          </div>
          <div className="flex items-center gap-2 justify-self-end">
            <Button variant="ghost" size="sm" aria-label="Notifications">
              <Bell className="size-4" />
            </Button>
            <NavUser />
          </div>
        </div>
        <div className="border-t border-border md:hidden">
          <div className="px-4 py-3">
            <SearchField />
          </div>
        </div>
        <div className="hidden border-t border-border md:block">
          <div className="mx-auto flex items-center gap-3 overflow-x-auto px-4 py-2 lg:px-6">
            <nav className="flex items-center gap-1">
              {navGroups.map((group) => (
                <NavDropdown key={group.title} group={group} />
              ))}
            </nav>
            <div className="ml-auto max-w-52">
              <OrganizationSwitcher />
            </div>
          </div>
        </div>
      </header>
      <main className="flex-1 px-4 py-6 pb-24 md:pb-6 lg:px-6">
        <div className="mx-auto max-w-5xl">
          <div className="min-h-[360px]" />
        </div>
      </main>
      {/* Mobile Bottom Navigation */}
      <BottomNav />
    </div>
  );
}

const bottomNavItems = [
  { label: "Overview", icon: LayoutDashboard, href: "#", isActive: true },
  { label: "Projects", icon: Briefcase, href: "#" },
  { label: "Team", icon: Users, href: "#" },
  { label: "Workspace", icon: Globe2, href: "#" },
];

function BottomNav() {
  return (
    <nav className="fixed inset-x-0 bottom-0 z-40 border-t border-border bg-background/95 backdrop-blur md:hidden">
      <div className="grid grid-cols-4">
        {bottomNavItems.map((item) => {
          const Icon = item.icon;
          return (
            <a
              key={item.label}
              href={item.href}
              className={cn(
                "flex flex-col items-center gap-1 py-2 text-xs",
                item.isActive
                  ? "text-primary"
                  : "text-muted-foreground hover:text-foreground",
              )}
            >
              <Icon className="size-5" aria-hidden="true" />
              <span className="sr-only">{item.label}</span>
              <span aria-hidden="true">{item.label}</span>
            </a>
          );
        })}
      </div>
    </nav>
  );
}

application-shell-4.source:
"use client";

import {
  BadgeCheck,
  BarChart3,
  Briefcase,
  ChevronDown,
  ChevronsUpDown,
  ClipboardList,
  Clock3,
  FileText,
  Folder,
  Globe2,
  HelpCircle,
  LayoutDashboard,
  LogOut,
  Menu,
  Search,
  Settings,
  Sparkles,
  Star,
  User,
  Users,
} from "lucide-react";
import * as React from "react";

import { cn } from "@/lib/utils";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { BlakeLogoIcon } from "../blake-logo-icon";

// Base nav item - used by simple sidebars
type NavItem = {
  label: string;
  icon: React.ComponentType<React.SVGProps<SVGSVGElement>>;
  href: string;
  isActive?: boolean;
  // Optional children for submenus (Sidebar3+)
  children?: NavItem[];
};

// Nav group with optional collapsible state
type NavGroup = {
  title: string;
  items: NavItem[];
  // Optional: default collapsed state (Sidebar2+)
  defaultOpen?: boolean;
};

// User data for footer (Sidebar6+)
type UserData = {
  name: string;
  email: string;
  avatar: string;
};

// Complete sidebar data structure
type SidebarData = {
  // Logo/branding (all sidebars)
  logo: {
    src: string;
    alt: string;
    title: string;
    description: string;
  };
  // Main navigation groups (all sidebars)
  navGroups: NavGroup[];
  // Footer navigation group (all sidebars)
  footerGroup: NavGroup;
  // User data for user footer (Sidebar6+)
  user?: UserData;
  // Workspaces for switcher (Sidebar7+)
  workspaces?: Array<{
    id: string;
    name: string;
    logo: string;
    plan: string;
  }>;
  // Currently active workspace (Sidebar7+)
  activeWorkspace?: string;
};

// Shared sidebar data - works with all sidebar variations
const sidebarData: SidebarData = {
  logo: {
    src: "https://placehold.co/64x64",
    alt: "BlakeUI",
    title: "BlakeUI",
    description: "The best UI library",
  },
  navGroups: [
    {
      title: "Overview",
      defaultOpen: true,
      items: [
        {
          label: "Dashboard",
          icon: LayoutDashboard,
          href: "#",
          isActive: true,
        },
        { label: "Tasks", icon: ClipboardList, href: "#" },
        { label: "Roadmap", icon: BarChart3, href: "#" },
      ],
    },
    {
      title: "Projects",
      defaultOpen: true,
      items: [
        {
          label: "Active Projects",
          icon: Briefcase,
          href: "#",
          children: [
            { label: "Project Alpha", icon: FileText, href: "#" },
            { label: "Project Beta", icon: FileText, href: "#" },
            { label: "Project Gamma", icon: FileText, href: "#" },
          ],
        },
        {
          label: "Archived",
          icon: Folder,
          href: "#",
          children: [
            { label: "2024 Archive", icon: FileText, href: "#" },
            { label: "2023 Archive", icon: FileText, href: "#" },
          ],
        },
      ],
    },
    {
      title: "Team",
      defaultOpen: false,
      items: [
        { label: "Members", icon: Users, href: "#" },
        { label: "Sprints", icon: Clock3, href: "#" },
        { label: "Approvals", icon: BadgeCheck, href: "#" },
        { label: "Reviews", icon: Star, href: "#" },
      ],
    },
    {
      title: "Workspace",
      defaultOpen: false,
      items: [
        { label: "Integrations", icon: Globe2, href: "#" },
        { label: "Automations", icon: Sparkles, href: "#" },
      ],
    },
  ],
  footerGroup: {
    title: "Support",
    items: [
      { label: "Help Center", icon: HelpCircle, href: "#" },
      { label: "Settings", icon: Settings, href: "#" },
    ],
  },
  user: {
    name: "John Doe",
    email: "john@example.com",
    avatar: "/avatar-1.webp",
  },
  workspaces: [
    {
      id: "1",
      name: "BlakeUI",
      logo: "/blake-logo-icon.svg",
      plan: "Enterprise",
    },
    {
      id: "2",
      name: "BlakeUI Templates",
      logo: "/blake-logo-icon.svg",
      plan: "Startup",
    },
    {
      id: "3",
      name: "BlakeUI Components",
      logo: "/blake-logo-icon.svg",
      plan: "Free",
    },
  ],
  activeWorkspace: "1",
};

// Desktop navigation dropdown for each group
const NavDropdown = ({
  group,
  isActive,
  onSelect,
}: {
  group: NavGroup;
  isActive: boolean;
  onSelect: () => void;
}) => {
  return (
    <Button
      variant="primary"
      className={cn("gap-1", isActive && "bg-brand/10")}
      onClick={onSelect}
    >
      {group.title}
    </Button>
  );
};

// Sub-navigation row showing items for active group
const SubNav = ({
  group,
  activeItem,
  onSelectItem,
}: {
  group: NavGroup;
  activeItem: NavItem | null;
  onSelectItem: (item: NavItem) => void;
}) => {
  return (
    <div className="flex h-10 items-center gap-1 overflow-x-auto border-b bg-muted/30 px-4 lg:px-6">
      {group.items.map((item) => {
        const Icon = item.icon;
        const isActive = activeItem?.label === item.label;
        const hasChildren = item.children && item.children.length > 0;

        if (hasChildren) {
          return (
            <DropdownMenu key={item.label}>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="primary"
                  size="sm"
                  className={cn(
                    "h-7 shrink-0 gap-1.5 text-sm",
                    isActive && "bg-accent text-accent-foreground",
                  )}
                >
                  <Icon className="size-4" />
                  {item.label}
                  <ChevronDown className="size-3" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="start">
                {item.children!.map((child) => {
                  const ChildIcon = child.icon;
                  return (
                    <DropdownMenuItem key={child.label} asChild>
                      <a href={child.href} className="flex items-center gap-2">
                        <ChildIcon className="size-4" />
                        {child.label}
                      </a>
                    </DropdownMenuItem>
                  );
                })}
              </DropdownMenuContent>
            </DropdownMenu>
          );
        }

        return (
          <Button
            key={item.label}
            variant="primary"
            size="sm"
            className={cn(
              "h-7 shrink-0 gap-1.5 text-sm",
              isActive && "bg-accent text-accent-foreground",
            )}
            onClick={() => onSelectItem(item)}
          >
            <Icon className="size-4" />
            {item.label}
          </Button>
        );
      })}
    </div>
  );
};

// Mobile navigation sheet
const MobileNav = ({
  activeGroupIndex,
  onSelectGroup,
}: {
  activeGroupIndex: number;
  onSelectGroup: (index: number) => void;
}) => {
  return (
    <Sheet>
      <SheetTrigger asChild>
        <Button variant="primary" size="sm" className="md:hidden">
          <Menu className="size-5" />
        </Button>
      </SheetTrigger>
      <SheetContent side="left" className="w-72 p-0">
        <SheetHeader className="px-4 pt-4">
          <SheetTitle className="flex items-center gap-2">
            <div className="flex aspect-square size-8 items-center justify-center rounded-sm bg-primary">
              <BlakeLogoIcon className="size-6 invert dark:invert-0" />
            </div>
            {sidebarData.logo.title}
          </SheetTitle>
        </SheetHeader>
        <ScrollArea className="min-h-0 flex-1">
          <nav className="flex flex-col gap-4 px-4 py-4">
            {sidebarData.navGroups.map((group, index) => (
              <div key={group.title}>
                <button
                  onClick={() => onSelectGroup(index)}
                  className={cn(
                    "mb-2 text-xs font-medium tracking-wider uppercase",
                    index === activeGroupIndex
                      ? "text-foreground"
                      : "text-muted-foreground",
                  )}
                >
                  {group.title}
                </button>
                {index === activeGroupIndex && (
                  <div className="flex flex-col gap-1">
                    {group.items.map((item) => {
                      const Icon = item.icon;
                      return (
                        <React.Fragment key={item.label}>
                          <a
                            href={item.href}
                            className={cn(
                              "flex items-center gap-2 rounded-md px-2 py-1.5 text-sm hover:bg-muted",
                              item.isActive && "bg-muted font-medium",
                            )}
                          >
                            <Icon className="size-4" />
                            {item.label}
                          </a>
                          {item.children?.map((child) => {
                            const ChildIcon = child.icon;
                            return (
                              <a
                                key={child.label}
                                href={child.href}
                                className="flex items-center gap-2 rounded-md py-1.5 pr-2 pl-8 text-sm hover:bg-muted"
                              >
                                <ChildIcon className="size-4" />
                                {child.label}
                              </a>
                            );
                          })}
                        </React.Fragment>
                      );
                    })}
                  </div>
                )}
              </div>
            ))}
            <Separator />
            <div>
              <div className="mb-2 text-xs font-medium tracking-wider text-muted-foreground uppercase">
                {sidebarData.footerGroup.title}
              </div>
              <div className="flex flex-col gap-1">
                {sidebarData.footerGroup.items.map((item) => {
                  const Icon = item.icon;
                  return (
                    <a
                      key={item.label}
                      href={item.href}
                      className="flex items-center gap-2 rounded-md px-2 py-1.5 text-sm hover:bg-muted"
                    >
                      <Icon className="size-4" />
                      {item.label}
                    </a>
                  );
                })}
              </div>
            </div>
          </nav>
        </ScrollArea>
      </SheetContent>
    </Sheet>
  );
};

// User dropdown
const NavUser = ({ user }: { user: UserData }) => {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="primary" className="gap-2 px-2">
          <Avatar className="size-8">
            <AvatarImage src={user.avatar} alt={user.name} />
            <AvatarFallback>
              {user.name
                .split(" ")
                .map((n) => n[0])
                .join("")}
            </AvatarFallback>
          </Avatar>
          <span className="hidden text-sm font-medium md:inline">
            {user.name}
          </span>
          <ChevronsUpDown className="hidden size-4 md:block" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-56">
        <DropdownMenuLabel className="font-normal">
          <div className="flex flex-col space-y-1">
            <p className="text-sm font-medium">{user.name}</p>
            <p className="text-xs text-muted-foreground">{user.email}</p>
          </div>
        </DropdownMenuLabel>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <User className="mr-2 size-4" />
          Account
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem>
          <LogOut className="mr-2 size-4" />
          Log out
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
};

interface ApplicationShell4Props {
  className?: string;
}

export function ApplicationShell4({ className }: ApplicationShell4Props) {
  const [activeGroupIndex, setActiveGroupIndex] = React.useState(0);
  const activeGroup = sidebarData.navGroups[activeGroupIndex];

  // Initialize activeItem to Dashboard (first item with isActive, or first item)
  const getDefaultActiveItem = (group: NavGroup) => {
    return group.items.find((item) => item.isActive) || group.items[0] || null;
  };

  const [activeItem, setActiveItem] = React.useState<NavItem | null>(
    getDefaultActiveItem(activeGroup),
  );

  return (
    <div className={cn("flex min-h-[520px] flex-col overflow-auto", className)}>
      <div className="flex min-w-fit flex-1 flex-col">
        {/* Top navigation bar */}
        <header className="sticky top-0 z-50 bg-background">
          <div className="flex h-14 items-center gap-2 border-b px-4 sm:gap-4 lg:px-6">
            {/* Mobile menu */}
            <MobileNav
              activeGroupIndex={activeGroupIndex}
              onSelectGroup={setActiveGroupIndex}
            />

            {/* Logo */}
            <a href="#" className="flex shrink-0 items-center gap-2">
              <BlakeLogoIcon className="size-8" />
              <span className="hidden font-semibold sm:inline">
                {sidebarData.logo.title}
              </span>
            </a>

            {/* Desktop navigation - group tabs */}
            <nav className="ml-4 hidden items-center gap-1 md:flex">
              {sidebarData.navGroups.map((group, index) => (
                <NavDropdown
                  key={group.title}
                  group={group}
                  isActive={index === activeGroupIndex}
                  onSelect={() => setActiveGroupIndex(index)}
                />
              ))}
            </nav>

            {/* Right side */}
            <div className="ml-auto flex shrink-0 items-center gap-2">
              <div className="relative hidden md:block">
                <Search className="absolute top-1/2 left-2.5 size-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  type="search"
                  placeholder="Search..."
                  className="h-9 w-64 pl-8"
                />
              </div>
              <Button variant="primary" size="sm" className="md:hidden">
                <Search className="size-5" />
              </Button>
              {sidebarData.user && <NavUser user={sidebarData.user} />}
            </div>
          </div>

          {/* Sub-navigation row */}
          <SubNav
            group={activeGroup}
            activeItem={activeItem}
            onSelectItem={setActiveItem}
          />
        </header>

        {/* Main content */}
        <main className="flex flex-1 flex-col gap-4 p-4 lg:p-6">
          <div className="h-[200px] flex-1 rounded-xl bg-muted/50 " />
        </main>
      </div>
    </div>
  );
}

