    getValue: () => ({ from: subDays(new Date(), 6), to: new Date() }),
  },
  {
    label: "Last 30 days",
    getValue: () => ({ from: subDays(new Date(), 29), to: new Date() }),
  },
  {
    label: "Last 3 months",
    getValue: () => ({ from: subMonths(new Date(), 3), to: new Date() }),
  },
];

const revenueConfig = {
  revenue: { label: "Revenue", color: "var(--chart-1)" },
} satisfies ChartConfig;
const sessionsConfig = {
  sessions: { label: "Sessions", color: "var(--chart-2)" },
} satisfies ChartConfig;
const conversionsConfig = {
  conversions: { label: "Conversions", color: "var(--chart-3)" },
} satisfies ChartConfig;

const ChartGroup14 = ({ className }: ChartGroup14Props) => {
  const [dateRange, setDateRange] = useState<DateRange | undefined>({
    from: subDays(new Date(), 29),
    to: new Date(),
  });
  const [selectedPreset, setSelectedPreset] = useState("Last 30 days");

  const filteredData = useMemo(() => {
    const from = dateRange?.from ?? subDays(new Date(), 29);
    const to = dateRange?.to ?? new Date();
    return generateDataForRange(from, to);
  }, [dateRange]);

  const stats = useMemo(() => {
    const totalRevenue = filteredData.reduce(
      (sum, item) => sum + item.revenue,
      0,
    );
    const totalSessions = filteredData.reduce(
      (sum, item) => sum + item.sessions,
      0,
    );
    const totalConversions = filteredData.reduce(
      (sum, item) => sum + item.conversions,
      0,
    );
    const avgBounceRate =
      filteredData.length > 0
        ? Math.round(
            filteredData.reduce((sum, item) => sum + item.bounceRate, 0) /
              filteredData.length,
          )
        : 0;
    const conversionRate =
      totalSessions > 0
        ? ((totalConversions / totalSessions) * 100).toFixed(1)
        : "0";
    return {
      totalRevenue,
      totalSessions,
      totalConversions,
      avgBounceRate,
      conversionRate,
    };
  }, [filteredData]);

  const handlePresetChange = (value: string) => {
    const preset = presetRanges.find((p) => p.label === value);
    if (preset) {
      setDateRange(preset.getValue());
      setSelectedPreset(value);
    }
  };

  return (
    <section className={cn("", className)}>
      <div className="container mx-auto space-y-6">
        {/* Header */}
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h2 className="text-2xl font-bold tracking-tight">
              Analytics Dashboard
            </h2>
            <p className="text-muted-foreground">
              Real-time insights into your business
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Select value={selectedPreset} onValueChange={handlePresetChange}>
              <SelectTrigger className="w-[140px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {presetRanges.map((preset) => (
                  <SelectItem key={preset.label} value={preset.label}>
                    {preset.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="primary">
                  <CalendarIcon className="mr-2 size-4" />
                  {dateRange?.from ? (
                    dateRange.to ? (
                      <>
                        {format(dateRange.from, "MMM d")} -{" "}
                        {format(dateRange.to, "MMM d")}
                      </>
                    ) : (
                      format(dateRange.from, "MMM d, yyyy")
                    )
                  ) : (
                    "Pick dates"
                  )}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="end">
                <Calendar
                  mode="range"
                  numberOfMonths={2}
                  selected={dateRange}
                  onSelect={(range) => {
                    setDateRange(range);
                    setSelectedPreset("Custom");
                  }}
                />
              </PopoverContent>
            </Popover>
          </div>
        </div>

        {/* Main Bento Grid */}
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
          {/* Stats Cards - Top Row */}
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div className="rounded-lg bg-primary/10 p-2">
                  <Activity className="size-5 text-primary" />
                </div>
                <Badge
                  variant="secondary"
                  className="bg-green-100 text-green-700"
                >
                  <TrendingUp className="mr-1 size-3" />
                  12.5%
                </Badge>
              </div>
              <div className="mt-3">
                <p className="text-sm text-muted-foreground">Total Revenue</p>
                <p className="text-2xl font-bold">
                  ${stats.totalRevenue.toLocaleString()}
                </p>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div className="rounded-lg bg-blue-100 p-2">
                  <Users className="size-5 text-blue-600" />
                </div>
                <Badge
                  variant="secondary"
                  className="bg-green-100 text-green-700"
                >
                  <TrendingUp className="mr-1 size-3" />
                  8.2%
                </Badge>
              </div>
              <div className="mt-3">
                <p className="text-sm text-muted-foreground">Total Sessions</p>
                <p className="text-2xl font-bold">
                  {stats.totalSessions.toLocaleString()}
                </p>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div className="rounded-lg bg-green-100 p-2">
                  <Zap className="size-5 text-green-600" />
                </div>
                <Badge
                  variant="secondary"
                  className="bg-green-100 text-green-700"
                >
                  <TrendingUp className="mr-1 size-3" />
                  5.4%
                </Badge>
              </div>
              <div className="mt-3">
                <p className="text-sm text-muted-foreground">Conversion Rate</p>
                <p className="text-2xl font-bold">{stats.conversionRate}%</p>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div className="rounded-lg bg-orange-100 p-2">
                  <Globe className="size-5 text-orange-600" />
                </div>
                <Badge variant="secondary" className="bg-red-100 text-red-700">
                  <TrendingDown className="mr-1 size-3" />
                  2.1%
                </Badge>
              </div>
              <div className="mt-3">
                <p className="text-sm text-muted-foreground">Bounce Rate</p>
                <p className="text-2xl font-bold">{stats.avgBounceRate}%</p>
              </div>
            </CardContent>
          </Card>

          {/* Revenue Chart - Spans 2 columns */}
          <Card className="md:col-span-2">
            <CardHeader className="pb-2">
              <CardTitle className="text-base">Revenue Trend</CardTitle>
            </CardHeader>
            <CardContent>
              <ChartContainer config={revenueConfig} className="h-52 w-full">
                <AreaChart
                  data={filteredData}
                  margin={{ top: 10, right: 10, left: 0, bottom: 0 }}
                >
                  <defs>
                    <linearGradient id="revGrad14" x1="0" y1="0" x2="0" y2="1">
                      <stop
                        offset="0%"
                        stopColor="var(--color-revenue)"
                        stopOpacity={0.3}
                      />
                      <stop
                        offset="100%"
                        stopColor="var(--color-revenue)"
                        stopOpacity={0}
                      />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis
                    dataKey="dateStr"
                    axisLine={false}
                    tickLine={false}
                    tickMargin={8}
                    fontSize={11}
                    interval="preserveStartEnd"
                  />
                  <YAxis
                    axisLine={false}
                    tickLine={false}
                    tickMargin={8}
                    fontSize={11}
                    tickFormatter={(v) => `$${v / 1000}k`}
                  />
                  <ChartTooltip content={<ChartTooltipContent />} />
                  <Area
                    type="monotone"
                    dataKey="revenue"
                    stroke="var(--color-revenue)"
                    strokeWidth={2}
                    fill="url(#revGrad14)"
                  />
                </AreaChart>
              </ChartContainer>
            </CardContent>
          </Card>

          {/* Traffic Channels - Donut */}
          <Card className="md:col-span-2">
            <CardHeader className="pb-2">
              <CardTitle className="text-base">Traffic Channels</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-6">
                <ChartContainer
                  config={channelConfig}
                  className="relative size-32 shrink-0"
                >
                  <PieChart>
                    <ChartTooltip
                      content={<ChartTooltipContent nameKey="name" hideLabel />}
                      cursor={false}
                    />
                    <Pie
                      data={channelData}
                      cx="50%"
                      cy="50%"
                      innerRadius={35}
                      outerRadius={55}
                      paddingAngle={2}
                      dataKey="value"
                      nameKey="name"
                      strokeWidth={0}
                    />
                  </PieChart>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <span className="text-lg font-bold">
                      {stats.totalSessions.toLocaleString()}
                    </span>
                  </div>
                </ChartContainer>
                <div className="flex-1 space-y-2">
                  {channelData.map((item, index) => (
                    <div
                      key={index}
                      className="flex items-center justify-between text-sm"
                    >
                      <div className="flex items-center gap-2">
                        <div
                          className="size-2 rounded-full"
                          style={{ backgroundColor: item.fill }}
                        />
                        <span className="text-muted-foreground">
                          {item.name}
                        </span>
                      </div>
                      <span className="font-medium">{item.value}%</span>
                    </div>
                  ))}
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Top Pages */}
          <Card className="md:col-span-2">
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-base">Top Pages</CardTitle>
              <Button variant="ghost" size="sm" className="text-xs">
                View all <ChevronRight className="ml-1 size-3" />
              </Button>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {topPages.map((page, index) => (
                  <div
                    key={index}
                    className="flex items-center justify-between"
                  >
                    <div className="flex items-center gap-3">
                      <span className="w-5 text-center text-sm text-muted-foreground">
                        {index + 1}
                      </span>
                      <span className="text-sm font-medium">{page.path}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="text-sm text-muted-foreground">
                        {page.views.toLocaleString()}
                      </span>
                      <span
                        className={cn(
                          "text-xs",
                          page.change >= 0 ? "text-green-600" : "text-red-600",
                        )}
                      >
                        {page.change >= 0 ? "+" : ""}
                        {page.change}%
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Active Users */}
          <Card className="md:col-span-2">
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-base">Most Active Users</CardTitle>
              <Button variant="ghost" size="sm" className="text-xs">
                View all <ChevronRight className="ml-1 size-3" />
              </Button>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {topUsers.map((user, index) => (
                  <div
                    key={index}
                    className="flex items-center justify-between"
                  >
                    <div className="flex items-center gap-3">
                      <Avatar className="size-8">
                        <AvatarImage src={user.avatar} alt={user.name} />
                        <AvatarFallback>
                          {user.name
                            .split(" ")
                            .map((n) => n[0])
                            .join("")}
                        </AvatarFallback>
                      </Avatar>
                      <div>
                        <p className="text-sm font-medium">{user.name}</p>
                        <p className="text-xs text-muted-foreground">
                          {user.email}
                        </p>
                      </div>
                    </div>
                    <Badge variant="secondary">{user.sessions} sessions</Badge>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </section>
  );
};

export { ChartGroup14 };

chart-group-15.source:
"use client";

import {
  addDays,
  differenceInDays,
  format,
  startOfDay,
  subDays,
} from "date-fns";
import {
  CalendarIcon,
  ChevronLeft,
  ChevronRight as ChevronRightIcon,
  Download,
  MoreHorizontal,
  RefreshCw,
  Settings,
  TrendingDown,
  TrendingUp,
} from "lucide-react";
import { useMemo, useState } from "react";
import type { DateRange } from "react-day-picker";
import {
  Area,
  AreaChart,
  Bar,
  BarChart,
  CartesianGrid,
  ComposedChart,
  Line,
  LineChart,
  Pie,
  PieChart,
  XAxis,
  YAxis,
} from "recharts";

import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  type ChartConfig,
  ChartContainer,
  ChartLegend,
  ChartLegendContent,
  ChartTooltip,
  ChartTooltipContent,
} from "@/components/ui/chart";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { cn } from "@/lib/utils";

interface ChartGroup15Props {
  className?: string;
}

// Seeded random number generator for consistent data
const seededRandom = (seed: number) => {
  const x = Math.sin(seed) * 10000;
  return x - Math.floor(x);
};

// Generate sample data for a specific date range
const generateDataForRange = (from: Date, to: Date) => {
  const data = [];
  let currentDate = new Date(from);
  let dayIndex = 0;

  while (currentDate <= to) {
    // Use date as seed for consistent data per date
    const seed = currentDate.getTime() / 86400000; // days since epoch
    const baseRevenue = 10000 + Math.sin(seed / 7) * 3000;
    const baseCost = 6000 + Math.sin(seed / 7) * 1500;

    data.push({
      date: new Date(currentDate),
      dateStr: format(currentDate, "MMM d"),
      revenue: Math.floor(baseRevenue + seededRandom(seed * 1) * 2000),
      cost: Math.floor(baseCost + seededRandom(seed * 2) * 1000),
      profit: Math.floor(
        baseRevenue - baseCost + seededRandom(seed * 3) * 1000,
      ),
      orders: Math.floor(seededRandom(seed * 4) * 80) + 40,
      aov: Math.floor(seededRandom(seed * 5) * 50) + 100,
      newCustomers: Math.floor(seededRandom(seed * 6) * 30) + 10,
      returning: Math.floor(seededRandom(seed * 7) * 50) + 30,
    });

    currentDate = addDays(currentDate, 1);
    dayIndex++;
  }
  return data;
};

// Generate hourly data (static - represents "today")
const hourlyData = Array.from({ length: 24 }, (_, i) => {
  const seed = i * 1000;
  return {
    hour: `${i.toString().padStart(2, "0")}:00`,
    visitors:
      Math.floor(seededRandom(seed) * 500) + (i >= 9 && i <= 17 ? 300 : 50),
    conversions:
      Math.floor(seededRandom(seed + 1) * 30) + (i >= 9 && i <= 17 ? 15 : 2),
  };
});

const deviceData = [
  { name: "Desktop", value: 58, fill: "var(--chart-1)" },
  { name: "Mobile", value: 32, fill: "var(--chart-2)" },
  { name: "Tablet", value: 10, fill: "var(--chart-3)" },
];

const deviceConfig = {
  Desktop: { label: "Desktop", color: "var(--chart-1)" },
  Mobile: { label: "Mobile", color: "var(--chart-2)" },
  Tablet: { label: "Tablet", color: "var(--chart-3)" },
} satisfies ChartConfig;

const revenueConfig = {
  revenue: { label: "Revenue", color: "var(--chart-1)" },
  cost: { label: "Cost", color: "var(--chart-2)" },
  profit: { label: "Profit", color: "var(--chart-3)" },
} satisfies ChartConfig;

const customerConfig = {
  newCustomers: { label: "New", color: "var(--chart-1)" },
  returning: { label: "Returning", color: "var(--chart-2)" },
} satisfies ChartConfig;

const hourlyConfig = {
  visitors: { label: "Visitors", color: "var(--chart-1)" },
  conversions: { label: "Conversions", color: "var(--chart-3)" },
} satisfies ChartConfig;

const ChartGroup15 = ({ className }: ChartGroup15Props) => {
  const [dateRange, setDateRange] = useState<DateRange | undefined>({
    from: subDays(new Date(), 29),
    to: new Date(),
  });
  const [chartView, setChartView] = useState<"revenue" | "profit" | "orders">(
    "revenue",
  );

  // Generate data dynamically based on selected date range
  const filteredData = useMemo(() => {
    if (!dateRange?.from) {
      return generateDataForRange(subDays(new Date(), 29), new Date());
    }
    const from = startOfDay(dateRange.from);
    const to = dateRange.to ? startOfDay(dateRange.to) : from;
    return generateDataForRange(from, to);
  }, [dateRange]);

  const stats = useMemo(() => {
    const totalRevenue = filteredData.reduce(
      (sum, item) => sum + item.revenue,
      0,
    );
    const totalCost = filteredData.reduce((sum, item) => sum + item.cost, 0);
    const totalProfit = filteredData.reduce(
      (sum, item) => sum + item.profit,
      0,
    );
    const totalOrders = filteredData.reduce(
      (sum, item) => sum + item.orders,
      0,
    );
    const avgAov =
      filteredData.length > 0
        ? Math.round(
            filteredData.reduce((sum, item) => sum + item.aov, 0) /
              filteredData.length,
          )
        : 0;
    const profitMargin =
      totalRevenue > 0 ? ((totalProfit / totalRevenue) * 100).toFixed(1) : "0";
    return {
      totalRevenue,
      totalCost,
      totalProfit,
      totalOrders,
      avgAov,
      profitMargin,
    };
  }, [filteredData]);

  const daysDiff =
    dateRange?.from && dateRange?.to
      ? differenceInDays(dateRange.to, dateRange.from) + 1
      : 30;

  const navigateRange = (direction: "prev" | "next") => {
    if (!dateRange?.from || !dateRange?.to) return;
    const shift = direction === "prev" ? -daysDiff : daysDiff;
    setDateRange({
      from: addDays(dateRange.from, shift),
      to: addDays(dateRange.to, shift),
    });
  };

  return (
    <section className={cn("", className)}>
      <div className="container mx-auto space-y-6">
        {/* Header */}
        <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
          <div>
            <h2 className="text-2xl font-bold tracking-tight">
              Business Analytics
            </h2>
            <p className="text-muted-foreground">
              {daysDiff} day{daysDiff !== 1 ? "s" : ""} selected
              {dateRange?.from &&
                ` · ${format(dateRange.from, "MMM d")} - ${format(dateRange.to || dateRange.from, "MMM d, yyyy")}`}
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            <div className="flex items-center rounded-lg border">
              <Button
                variant="ghost"
                size="sm"
                className="rounded-r-none"
                onClick={() => navigateRange("prev")}
              >
                <ChevronLeft className="size-4" />
              </Button>
              <Popover>
                <PopoverTrigger asChild>
                  <Button
                    variant="ghost"
                    className="rounded-none border-x px-3"
                  >
                    <CalendarIcon className="mr-2 size-4" />
                    {dateRange?.from
                      ? format(dateRange.from, "MMM d")
                      : "Start"}{" "}
                    - {dateRange?.to ? format(dateRange.to, "MMM d") : "End"}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="center">
                  <Calendar
                    mode="range"
                    numberOfMonths={2}
                    selected={dateRange}
                    onSelect={setDateRange}
                  />
                </PopoverContent>
              </Popover>
              <Button
                variant="ghost"
                size="sm"
                className="rounded-l-none"
                onClick={() => navigateRange("next")}
              >
                <ChevronRightIcon className="size-4" />
              </Button>
            </div>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="primary" size="sm">
                  <MoreHorizontal className="size-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem>
                  <Download className="mr-2 size-4" /> Export CSV
                </DropdownMenuItem>
                <DropdownMenuItem>
                  <RefreshCw className="mr-2 size-4" /> Refresh
                </DropdownMenuItem>
                <DropdownMenuItem>
                  <Settings className="mr-2 size-4" /> Settings
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>

        {/* Stats Row */}
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-5">
          {[
            {
              label: "Revenue",
              value: `$${stats.totalRevenue.toLocaleString()}`,
              change: 12.5,
            },
            {
              label: "Cost",
              value: `$${stats.totalCost.toLocaleString()}`,
              change: 8.2,
            },
            {
              label: "Profit",
              value: `$${stats.totalProfit.toLocaleString()}`,
              change: 18.3,
            },
            {
              label: "Orders",
              value: stats.totalOrders.toLocaleString(),
              change: 5.7,
            },
            {
              label: "Profit Margin",
              value: `${stats.profitMargin}%`,
              change: 2.1,
            },
          ].map((stat, index) => (
            <Card key={index}>
              <CardContent className="pt-6">
                <p className="text-sm text-muted-foreground">{stat.label}</p>
                <div className="flex items-baseline justify-between">
                  <p className="text-2xl font-bold">{stat.value}</p>
                  <span
                    className={cn(
                      "flex items-center text-sm",
                      stat.change >= 0 ? "text-green-600" : "text-red-600",
                    )}
                  >
                    {stat.change >= 0 ? (
                      <TrendingUp className="mr-1 size-3" />
                    ) : (
                      <TrendingDown className="mr-1 size-3" />
                    )}
                    {stat.change >= 0 ? "+" : ""}
                    {stat.change}%
                  </span>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Main Charts Bento */}
        <div className="grid gap-4 lg:grid-cols-3">
          {/* Revenue/Profit/Orders Chart - Large */}
          <Card className="lg:col-span-2">
            <Tabs
              value={chartView}
              onValueChange={(v) => setChartView(v as typeof chartView)}
            >
              <CardHeader className="flex flex-row items-center justify-between pb-2">
                <div>
                  <CardTitle className="text-base">
                    Performance Overview
                  </CardTitle>
                  <CardDescription>
                    Revenue, cost, and profit trends
                  </CardDescription>
                </div>
                <TabsList className="h-8">
                  <TabsTrigger value="revenue" className="text-xs">
                    Revenue
                  </TabsTrigger>
                  <TabsTrigger value="profit" className="text-xs">
                    Profit
                  </TabsTrigger>
                  <TabsTrigger value="orders" className="text-xs">
                    Orders
                  </TabsTrigger>
                </TabsList>
              </CardHeader>
              <CardContent>
                <TabsContent value="revenue" className="mt-0">
                  <ChartContainer
                    config={revenueConfig}
                    className="h-72 w-full"
                  >
                    <AreaChart
                      data={filteredData}
                      margin={{ top: 10, right: 10, left: 0, bottom: 0 }}
                    >
                      <defs>
                        <linearGradient
                          id="revGrad15"
