"use client";

import type {
  ColumnFiltersState,
  RowSelectionState,
  VisibilityState,
} from "@tanstack/react-table";
import {
  type Column,
  type ColumnDef,
  flexRender,
  getCoreRowModel,
  getFacetedRowModel,
  getFacetedUniqueValues,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  type SortingState,
  type Table as TableType,
  useReactTable,
} from "@tanstack/react-table";
import {
  ArrowDown,
  ArrowUp,
  CheckCheckIcon,
  CheckCircle,
  ChevronLeft,
  ChevronRight,
  ChevronsLeft,
  ChevronsRight,
  ChevronsUpDown,
  Clock,
  Footprints,
  ListFilterIcon,
  LoaderIcon,
  Package,
  PackageIcon,
  PieChart,
  RefreshCcw,
  Shirt,
  ShoppingBag,
  Smartphone,
} from "lucide-react";
import * as React from "react";
import { z } from "zod";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { cn } from "@/lib/utils";

type UseDataTableOptions<TData> = {
  data: Array<TData>;
  columns: Array<ColumnDef<TData, unknown>>;
  getRowId?: (row: TData) => string;
  initialSorting?: SortingState;
  initialGlobalFilter?: string;
  initialFilters?: ColumnFiltersState;
  initialVisibility?: VisibilityState;
  initialSelection?: RowSelectionState;
  enableRowSelection?: boolean;
};
export function useDataTable<TData>(options: UseDataTableOptions<TData>) {
  const {
    data,
    columns,
    getRowId,
    initialSorting = [],
    initialFilters = [],
    initialGlobalFilter = "",
    initialVisibility = {},
    initialSelection = {},
    enableRowSelection = true,
  } = options;

  const [sorting, setSorting] = React.useState<SortingState>(initialSorting);
  const [columnFilters, setColumnFilters] =
    React.useState<ColumnFiltersState>(initialFilters);
  const [globalFilter, setGlobalFilter] =
    React.useState<string>(initialGlobalFilter);
  const [columnVisibility, setColumnVisibility] =
    React.useState<VisibilityState>(initialVisibility);
  const [rowSelection, setRowSelection] =
    React.useState<RowSelectionState>(initialSelection);

  const table = useReactTable({
    data,
    columns,
    getRowId,
    state: {
      sorting,
      columnFilters,
      globalFilter,
      columnVisibility,
      rowSelection,
    },
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onRowSelectionChange: setRowSelection,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    onGlobalFilterChange: setGlobalFilter,
    onColumnVisibilityChange: setColumnVisibility,
    getFacetedRowModel: getFacetedRowModel(),
    getFacetedUniqueValues: getFacetedUniqueValues(),
    enableRowSelection,
  });

  return {
    table,
    columnFilters,
    setColumnFilters,
    sorting,
    setSorting,
    globalFilter,
    setGlobalFilter,
    columnVisibility,
    setColumnVisibility,
    rowSelection,
    setRowSelection,
  };
}

type DataTableColumnHeaderProps<TData, TValue> = {
  column: Column<TData, TValue>;
  title: string;
};

export const DataTableColumnHeader = <TData, TValue>({
  column,
  title,
}: DataTableColumnHeaderProps<TData, TValue>) => {
  const canSort = column.getCanSort();
  const sorted = column.getIsSorted();

  if (!canSort) {
    return (
      <span className="flex h-8 items-center text-sm font-medium text-foreground">
        {title}
      </span>
    );
  }

  return (
    <Button
      variant="ghost"
      size="sm"
      className="flex h-8 items-center gap-2 px-0 text-sm font-medium text-foreground"
      onClick={() => column.toggleSorting(sorted === "asc")}
    >
      <span>{title}</span>
      {sorted === "desc" ? (
        <ArrowDown className="h-4 w-4" />
      ) : sorted === "asc" ? (
        <ArrowUp className="h-4 w-4" />
      ) : (
        <ChevronsUpDown className="h-4 w-4 opacity-50" />
      )}
    </Button>
  );
};

type DataTablePaginationProps<TData> = {
  table: TableType<TData>;
  pageSizeOptions?: number[];
};

export const DataTablePagination = <TData,>({
  table,
  pageSizeOptions = [10, 20, 30, 40, 50],
}: DataTablePaginationProps<TData>) => {
  const currentPage = table.getState().pagination.pageIndex;
  const pageSize = table.getState().pagination.pageSize;
  const totalRows = table.getFilteredRowModel().rows.length;
  const pageCount = table.getPageCount();

  const startRow = currentPage * pageSize + 1;
  const endRow = Math.min((currentPage + 1) * pageSize, totalRows);

  const relevantPageSizes = pageSizeOptions.filter(
    (size) => size <= totalRows || size === pageSize,
  );

  return (
    <div className="flex flex-col gap-4 px-2 py-4 sm:flex-row sm:items-center sm:justify-between">
      <div className="flex-1 text-center text-sm text-muted-foreground sm:text-left">
        <span className="font-medium">
          {totalRows === 0 ? (
            "No results"
          ) : (
            <>
              Showing {startRow} to {endRow} of {totalRows}{" "}
              {totalRows === 1 ? "row" : "rows"}
            </>
          )}
        </span>
      </div>

      <div className="flex flex-col items-center gap-4 sm:flex-row sm:gap-6 lg:gap-8">
        <div className="flex items-center gap-2">
          <p className="text-sm font-medium whitespace-nowrap">Rows per page</p>
          <Select
            value={`${pageSize}`}
            onValueChange={(value) => {
              table.setPageSize(Number(value));
            }}
            disabled={totalRows === 0}
          >
            <SelectTrigger className="h-8 w-[70px]">
              <SelectValue placeholder={pageSize} />
            </SelectTrigger>
            <SelectContent side="top">
              {relevantPageSizes.map((size) => (
                <SelectItem key={size} value={`${size}`}>
                  {size}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div className="flex items-center gap-4">
          <div className="text-sm font-medium whitespace-nowrap">
            Page {currentPage + 1} of {pageCount}
          </div>

          <div className="flex items-center gap-1">
            <Button
              variant="primary"
              size="sm"
              className="hidden size-8 lg:flex"
              onClick={() => table.setPageIndex(0)}
              disabled={currentPage === 0 || totalRows === 0}
              aria-label="Go to first page"
            >
              <ChevronsLeft className="h-4 w-4" />
            </Button>
            <Button
              variant="primary"
              size="sm"
              className="size-8"
              onClick={() => table.previousPage()}
              disabled={!table.getCanPreviousPage()}
              aria-label="Go to previous page"
            >
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <Button
              variant="primary"
              size="sm"
              className="size-8"
              onClick={() => table.nextPage()}
              disabled={!table.getCanNextPage()}
              aria-label="Go to next page"
            >
              <ChevronRight className="h-4 w-4" />
            </Button>
            <Button
              variant="primary"
              size="sm"
              className="hidden size-8 lg:flex"
              onClick={() => table.setPageIndex(pageCount - 1)}
              disabled={currentPage === pageCount - 1 || totalRows === 0}
              aria-label="Go to last page"
            >
              <ChevronsRight className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

interface DataTableButtonFilterOption {
  label: string;
  value: string;
  icon?: React.ComponentType<{ className?: string }>;
}

interface DataTableButtonFilterProps<TData, TValue> {
  column?: Column<TData, TValue>;
  title?: string;
  options: DataTableButtonFilterOption[];
  align?: "start" | "center" | "end";
}

export function DataTableButtonFilter<TData, TValue>({
  column,
  title = "Filter",
  options,
  align = "end",
}: DataTableButtonFilterProps<TData, TValue>) {
  const facets = column?.getFacetedUniqueValues();

  const facetCounts = React.useMemo(() => {
    if (!facets || !column) return null;
    const map = new Map<string, number>();
    facets.forEach((count, key) => {
      const numeric = Number(count);
      const stringKey = String(key);
      map.set(stringKey, numeric);
      map.set(stringKey.toLowerCase(), numeric);
    });
    return map;
  }, [facets, column]);

  const filterValue = column?.getFilterValue();
  const selectedValues = React.useMemo(() => {
    if (filterValue == null) return new Set<string>();
    const values = Array.isArray(filterValue)
      ? filterValue.filter(Boolean).map(String)
      : [String(filterValue)];
    return new Set(values.map((value) => value.toLowerCase()));
  }, [filterValue]);
  const selectedCount = selectedValues.size;

  const handleValueChange = React.useCallback(
    (value: string, checked: boolean) => {
      if (!column) return;
      const currentValue = column.getFilterValue();
      const raw = Array.isArray(currentValue)
        ? currentValue.map(String)
        : currentValue
          ? [String(currentValue)]
          : [];
      const next = new Set(raw);

      if (checked) {
        next.add(value);
      } else {
        next.delete(value);
      }

      column.setFilterValue(next.size ? Array.from(next) : undefined);
    },
    [column],
  );

  const clearFilters = React.useCallback(() => {
    if (!column) return;
    column.setFilterValue(undefined);
  }, [column]);

  if (!column) {
    return null;
  }

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          variant="primary"
          size="sm"
          className={cn("h-8 gap-2 px-3", selectedCount > 0 && "bg-primary/5")}
        >
          <ListFilterIcon className="size-4" />
          <span className="text-sm font-medium">Filter</span>
          {selectedCount > 0 && (
            <Badge
              variant="secondary"
              className="rounded-sm px-1 text-[11px] font-normal"
            >
              {selectedCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent
        align={align}
        className="w-auto min-w-36 space-y-3"
        sideOffset={8}
      >
        <div className="space-y-3">
          <p className="text-xs font-semibold text-muted-foreground/70 uppercase">
            {title}
          </p>
          <div className="space-y-2">
            {options.map((option, index) => {
              const checkboxId = `${column.id ?? "filter"}-${index}`;
              const isSelected = selectedValues.has(option.value.toLowerCase());
              const OptionIcon = option.icon;
              const count =
                facetCounts?.get(option.value) ??
                facetCounts?.get(option.value.toLowerCase());

              return (
                <div
                  key={option.value}
                  className={cn(
                    "flex items-center gap-3 rounded-lg px-2 py-1.5 transition-colors",
                    isSelected ? "bg-muted" : "hover:bg-muted/70",
                  )}
                >
                  <Checkbox
                    id={checkboxId}
                    checked={isSelected}
                    onCheckedChange={(checked) =>
                      handleValueChange(option.value, Boolean(checked))
                    }
                    aria-label={`Toggle ${option.label}`}
                  />
                  <Label
                    htmlFor={checkboxId}
                    className="flex w-full items-center justify-between gap-3 text-sm"
                  >
                    <span className="flex items-center gap-2">
                      {OptionIcon && (
                        <OptionIcon className="size-3.5 text-muted-foreground" />
                      )}
                      {option.label}
                    </span>
                    {typeof count === "number" && !Number.isNaN(count) && (
                      <span className="text-xs text-muted-foreground">
                        {count}
                      </span>
                    )}
                  </Label>
                </div>
              );
            })}
          </div>
        </div>
        <Button
          variant="primary"
          size="sm"
          type="button"
          className={cn(
            "h-8 w-full justify-center rounded-md border-dashed bg-muted/40 text-xs font-semibold tracking-wide text-muted-foreground uppercase",
            selectedCount === 0 &&
              "border-muted/40 bg-muted/10 text-muted-foreground/70",
          )}
          onClick={clearFilters}
          disabled={selectedCount === 0}
        >
          Clear filters
        </Button>
      </PopoverContent>
    </Popover>
  );
}

interface DataTableTabbarProps<TData> extends React.ComponentProps<"div"> {
  _table: TableType<TData>;
  search?: React.ReactNode;
  filter?: React.ReactNode;
}
export function DataTableTabbar<TData>({
  _table,
  children,
  search,
  filter,
  className,
  ...props
}: DataTableTabbarProps<TData>) {
  return (
    <div
      className={cn("flex items-center justify-between py-4", className)}
      {...props}
    >
      <div className="flex flex-1 items-center gap-2">{children}</div>
      <div className="flex w-full items-center gap-2 sm:w-auto">
        {search}
        {filter}
      </div>
    </div>
  );
}

