"use client";

import {
  type Column,
  type ColumnDef,
  type ColumnPinningState,
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  type SortingState,
  useReactTable,
  type VisibilityState,
} from "@tanstack/react-table";
import {
  ArrowDown,
  ArrowUp,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  Columns3,
  EyeOff,
  Footprints,
  PackageIcon,
  Pin,
  PinOff,
  Shirt,
  ShoppingBag,
  Smartphone,
} from "lucide-react";
import type { CSSProperties } from "react";
import * as React from "react";
import { z } from "zod";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { cn } from "@/lib/utils";

type UseDataTableOptions<TData> = {
  data: Array<TData>;
  columns: Array<ColumnDef<TData, unknown>>;
  getRowId?: (row: TData) => string;
  initialSorting?: SortingState;
  initialColumnPinning?: ColumnPinningState;
};

export function useDataTable<TData>(options: UseDataTableOptions<TData>) {
  const {
    data,
    columns,
    getRowId,
    initialSorting = [],
    initialColumnPinning = {},
  } = options;

  const [sorting, setSorting] = React.useState<SortingState>(initialSorting);
  const [columnOrder, setColumnOrder] = React.useState<string[]>(
    columns.map((col) => col.id as string),
  );
  const [columnPinning, setColumnPinning] =
    React.useState<ColumnPinningState>(initialColumnPinning);
  const [columnVisibility, setColumnVisibility] =
    React.useState<VisibilityState>({});

  const table = useReactTable({
    data,
    columns,
    getRowId,
    state: {
      sorting,
      columnOrder,
      columnPinning,
      columnVisibility,
    },
    onSortingChange: setSorting,
    onColumnOrderChange: setColumnOrder,
    onColumnPinningChange: setColumnPinning,
    onColumnVisibilityChange: setColumnVisibility,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
  });

  return {
    table,
    sorting,
    setSorting,
    columnOrder,
    setColumnOrder,
    columnPinning,
    setColumnPinning,
    columnVisibility,
    setColumnVisibility,
  };
}

type DataTableColumnHeaderProps<TData, TValue> = {
  column: Column<TData, TValue>;
  title: string;
  columnId: string;
  columnOrder: string[];
  allColumns: Column<TData, unknown>[];
  onMoveColumn: (columnId: string, direction: "left" | "right") => void;
  onPinColumn: (columnId: string, position: "left" | "right" | false) => void;
  onHideColumn: (columnId: string) => void;
};

export const DataTableColumnHeader = <TData, TValue>({
  column,
  title,
  columnId,
  columnOrder,
  allColumns,
  onMoveColumn,
  onPinColumn,
  onHideColumn,
}: DataTableColumnHeaderProps<TData, TValue>) => {
  const canSort = column.getCanSort();
  const sorted = column.getIsSorted();
  const currentIndex = columnOrder.indexOf(columnId);
  const isFirst = currentIndex === 0;
  const isLast = currentIndex === columnOrder.length - 1;
  const isPinned = column.getIsPinned();

  return (
    <div className="flex items-center justify-between gap-2">
      <span className="truncate text-sm font-medium">{title}</span>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button
            variant="ghost"
            size="sm"
            className="h-7 w-7 p-0 hover:bg-muted data-[state=open]:bg-muted"
          >
            <ChevronDown className="h-4 w-4" />
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start" className="w-48">
          {canSort && (
            <>
              <DropdownMenuItem
                onClick={() => column.toggleSorting(false)}
                className="flex items-center gap-2"
              >
                <ArrowUp className="h-4 w-4" />
                <span>Asc</span>
                {sorted === "asc" && (
                  <span className="ml-auto text-primary">✓</span>
                )}
              </DropdownMenuItem>
              <DropdownMenuItem
                onClick={() => column.toggleSorting(true)}
                className="flex items-center gap-2"
              >
                <ArrowDown className="h-4 w-4" />
                <span>Desc</span>
                {sorted === "desc" && (
                  <span className="ml-auto text-primary">✓</span>
                )}
              </DropdownMenuItem>
              <DropdownMenuSeparator />
            </>
          )}

          <DropdownMenuItem
            onClick={() => onPinColumn(columnId, "left")}
            className="flex items-center gap-2"
          >
            <Pin className="h-4 w-4 rotate-[-45deg]" />
            <span>Pin to left</span>
            {isPinned === "left" && (
              <span className="ml-auto text-primary">✓</span>
            )}
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={() => onPinColumn(columnId, "right")}
            className="flex items-center gap-2"
          >
            <Pin className="h-4 w-4 rotate-45" />
            <span>Pin to right</span>
            {isPinned === "right" && (
              <span className="ml-auto text-primary">✓</span>
            )}
          </DropdownMenuItem>
          {isPinned && (
            <DropdownMenuItem
              onClick={() => onPinColumn(columnId, false)}
              className="flex items-center gap-2"
            >
              <PinOff className="h-4 w-4" />
              <span>Unpin</span>
            </DropdownMenuItem>
          )}

          <DropdownMenuSeparator />

          <DropdownMenuItem
            onClick={() => onMoveColumn(columnId, "left")}
            disabled={isFirst}
            className="flex items-center gap-2"
          >
            <ChevronLeft className="h-4 w-4" />
            <span>Move to Left</span>
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={() => onMoveColumn(columnId, "right")}
            disabled={isLast}
            className="flex items-center gap-2"
          >
            <ChevronRight className="h-4 w-4" />
            <span>Move to Right</span>
          </DropdownMenuItem>

          <DropdownMenuSeparator />

          <DropdownMenuSub>
            <DropdownMenuSubTrigger className="flex items-center gap-2">
              <Columns3 className="h-4 w-4" />
              <span>Columns</span>
            </DropdownMenuSubTrigger>
            <DropdownMenuSubContent className="w-48">
              {allColumns
                .filter((col) => col.getCanHide())
                .map((col) => {
                  return (
                    <DropdownMenuCheckboxItem
                      key={col.id}
                      checked={col.getIsVisible()}
                      onCheckedChange={(value) => col.toggleVisibility(!!value)}
                    >
                      {typeof col.columnDef.header === "string"
                        ? col.columnDef.header
                        : col.id}
                    </DropdownMenuCheckboxItem>
                  );
                })}
            </DropdownMenuSubContent>
          </DropdownMenuSub>

          <DropdownMenuItem
            onClick={() => onHideColumn(columnId)}
            className="flex items-center gap-2"
          >
            <EyeOff className="h-4 w-4" />
            <span>Hide column</span>
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
};

