} from "@/components/ui/popover";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

interface InputData {
  firstName: string;
  lastName: string;
  email: string;
  mobile: string;
  country: string;
  city: string;
}

const DUMMY_INPUT_DATA: InputData[] = [
  {
    firstName: "Alex",
    lastName: "Morgan",
    email: "alex.morgan@acme.co",
    mobile: "5551234567",
