                  </div>
                </CardHeader>
                <CardContent className="space-y-2">
                  <CardDescription className="flex items-center gap-2 text-sm">
                    <Mail className="size-4" />
                    {member.email}
                  </CardDescription>
                  <p className="text-xs text-muted-foreground">
                    Joined {member.joinedAt}
                  </p>
                </CardContent>
              </Card>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export { SettingsMembers3 };

settings-members-4.source:
"use client";

import { Trash2, UserPlus } from "lucide-react";
import { useMemo, useState } from "react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { cn } from "@/lib/utils";

interface Member {
  id: string;
  name: string;
  email: string;
  role: string;
  avatar?: string;
  status: "active" | "pending";
}

interface SettingsMembers4Props {
  heading?: string;
  description?: string;
  members?: Member[];
  className?: string;
}

const SettingsMembers4 = ({
  heading = "Organization Members",
  description = "Manage who has access to this organization.",
  members = [
    {
      id: "1",
      name: "Nina Kowalski",
      email: "nina.k@startup.co",
      role: "Owner",
      avatar:
        "https://i.pravatar.cc/150?img=1",
      status: "active",
    },
    {
      id: "2",
      name: "James Liu",
      email: "james.l@startup.co",
      role: "Admin",
      avatar:
        "https://i.pravatar.cc/150?img=8",
      status: "active",
    },
    {
      id: "3",
      name: "Rachel Green",
      email: "rachel.g@startup.co",
      role: "Developer",
      avatar:
        "https://i.pravatar.cc/150?img=9",
      status: "active",
    },
    {
      id: "4",
      name: "Omar Hassan",
      email: "omar.h@startup.co",
      role: "Developer",
      status: "pending",
    },
    {
      id: "5",
      name: "Lisa Wang",
      email: "lisa.w@startup.co",
      role: "Designer",
      avatar:
        "https://i.pravatar.cc/150?img=10",
      status: "active",
    },
  ],
  className,
}: SettingsMembers4Props) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [isInviteOpen, setIsInviteOpen] = useState(false);

  const allSelected = selectedIds.length === members.length;
  const someSelected = selectedIds.length > 0 && !allSelected;

  const toggleAll = () => {
    if (allSelected) {
      setSelectedIds([]);
    } else {
      setSelectedIds(members.map((m) => m.id));
    }
  };

  const toggleMember = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((i) => i !== id) : [...prev, id],
    );
  };

  const selectedCount = selectedIds.length;

  const roleStats = useMemo(() => {
    const stats: Record<string, number> = {};
    members.forEach((m) => {
      stats[m.role] = (stats[m.role] || 0) + 1;
    });
    return stats;
  }, [members]);

  return (
    <section className="">
      <div className="container max-w-3xl mx-auto">
        <div className={cn("space-y-6", className)}>
          <div className="space-y-1">
            <h2 className="text-2xl font-semibold tracking-tight">{heading}</h2>
            <p className="text-sm text-muted-foreground">{description}</p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            {Object.entries(roleStats).map(([role, count]) => (
              <Badge key={role} variant="outline" className="font-normal">
                {role}: {count}
              </Badge>
            ))}
          </div>

          <div className="rounded-lg border">
            <div className="flex items-center justify-between border-b bg-muted/50 px-4 py-3">
              <div className="flex items-center gap-3">
                <Checkbox
                  checked={allSelected}
                  onCheckedChange={toggleAll}
                  aria-label="Select all"
                  {...(someSelected && { "data-state": "indeterminate" })}
                />
                <span className="text-sm font-medium">
                  {selectedCount > 0
                    ? `${selectedCount} selected`
                    : `${members.length} members`}
                </span>
              </div>
              <div className="flex items-center gap-2">
                {selectedCount > 0 && (
                  <Button
                    variant="primary"
                    size="sm"
                    className="text-destructive hover:bg-destructive/10"
                    onClick={() => setSelectedIds([])}
                  >
                    <Trash2 className="size-4" />
                    Remove
                  </Button>
                )}
                <Dialog open={isInviteOpen} onOpenChange={setIsInviteOpen}>
                  <DialogTrigger asChild>
                    <Button size="sm">
                      <UserPlus className="size-4" />
                      Invite
                    </Button>
                  </DialogTrigger>
                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>Invite Member</DialogTitle>
                      <DialogDescription>
                        Add a new member to your organization.
                      </DialogDescription>
                    </DialogHeader>
                    <form
                      onSubmit={(e) => {
                        e.preventDefault();
                        setIsInviteOpen(false);
                      }}
                      className="space-y-4"
                    >
                      <div className="space-y-2">
                        <Label htmlFor="invite-email">Email</Label>
                        <Input
                          id="invite-email"
                          type="email"
                          placeholder="name@company.com"
                        />
                      </div>
                      <div className="space-y-2">
                        <Label htmlFor="invite-role">Role</Label>
                        <Select defaultValue="developer">
                          <SelectTrigger id="invite-role">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="admin">Admin</SelectItem>
                            <SelectItem value="developer">Developer</SelectItem>
                            <SelectItem value="designer">Designer</SelectItem>
                            <SelectItem value="viewer">Viewer</SelectItem>
                          </SelectContent>
                        </Select>
                      </div>
                      <DialogFooter>
                        <Button
                          type="button"
                          variant="primary"
                          onClick={() => setIsInviteOpen(false)}
                        >
                          Cancel
                        </Button>
                        <Button type="submit">Send Invite</Button>
                      </DialogFooter>
                    </form>
                  </DialogContent>
                </Dialog>
              </div>
            </div>

            <ul className="divide-y">
              {members.map((member) => (
                <li
                  key={member.id}
                  className={cn(
                    "flex items-center gap-4 px-4 py-3 transition-colors",
                    selectedIds.includes(member.id) && "bg-muted/30",
                  )}
                >
                  <Checkbox
                    checked={selectedIds.includes(member.id)}
                    onCheckedChange={() => toggleMember(member.id)}
                    aria-label={`Select ${member.name}`}
                  />
                  <Avatar className="size-9">
                    <AvatarImage src={member.avatar} alt={member.name} />
                    <AvatarFallback className="text-xs">
                      {member.name
                        .split(" ")
                        .map((n) => n[0])
                        .join("")}
                    </AvatarFallback>
                  </Avatar>
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2">
                      <p className="truncate text-sm font-medium">
                        {member.name}
                      </p>
                      {member.status === "pending" && (
                        <Badge
                          variant="secondary"
                          className="bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400"
                        >
                          Pending
                        </Badge>
                      )}
                    </div>
                    <p className="truncate text-xs text-muted-foreground">
                      {member.email}
                    </p>
                  </div>
                  <Badge variant="outline" className="shrink-0 font-normal">
                    {member.role}
                  </Badge>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>
    </section>
  );
};

export { SettingsMembers4 };

settings-profile-2.source:
"use client";

import { Camera, Github, Globe, Linkedin, Twitter } from "lucide-react";
import { useState } from "react";

import { FileUpload, FileUploadTrigger } from "@/components/ui/file-upload";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

interface ProfileFormData {
  name: string;
  email: string;
  username: string;
  avatar?: string;
  bio?: string;
  jobTitle?: string;
  company?: string;
  location?: string;
  website?: string;
  socialLinks?: {
    twitter?: string;
    linkedin?: string;
    github?: string;
  };
}

interface SettingsProfile2Props {
  defaultValues?: Partial<ProfileFormData>;
  onSave?: (data: ProfileFormData) => void;
  className?: string;
}

const SettingsProfile2 = ({
  defaultValues = {
    name: "Alex Morgan",
    email: "alex.morgan@blakeui.com",
    username: "alexmorgan",
    avatar: "/avatar-1.webp",
    bio: "Designer and front-end engineer building polished UIs with BlakeUI. Interested in design systems, accessibility, and shipping fast without sacrificing quality.",
    jobTitle: "Product Designer",
    company: "BlakeUI",
    location: "San Francisco, CA",
    website: "https://blakeui.com",
    socialLinks: {
      twitter: "blakeui",
      linkedin: "blakeui",
      github: "blakeui",
    },
  },
  className,
}: SettingsProfile2Props) => {
  const [avatarFiles, setAvatarFiles] = useState<File[]>([]);

  const initials = defaultValues.name
    ?.split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase();

  const avatarPreview =
    avatarFiles.length > 0
      ? URL.createObjectURL(avatarFiles[0])
      : defaultValues.avatar;

  return (
    <Card className={cn("w-full max-w-2xl", className)}>
      <CardHeader>
        <CardTitle>Edit Profile</CardTitle>
        <CardDescription>
          Manage your public profile information
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-8">
        {/* Avatar Section */}
        <FileUpload
          value={avatarFiles}
          onValueChange={setAvatarFiles}
          accept="image/*"
          maxFiles={1}
          maxSize={2 * 1024 * 1024}
        >
          <div className="flex flex-col items-center gap-4 sm:flex-row sm:items-start">
            <div className="relative">
              <Avatar className="size-24">
                <AvatarImage
                  src={avatarPreview}
                  alt={defaultValues.name}
                  className="object-cover"
                />
                <AvatarFallback className="text-2xl font-semibold">
                  {initials}
                </AvatarFallback>
              </Avatar>
              <FileUploadTrigger asChild>
                <Button
                  size="sm"
                  variant="secondary"
                  className="absolute -right-1 -bottom-1 size-8 rounded-full shadow-md"
                >
                  <Camera className="size-4" />
                </Button>
              </FileUploadTrigger>
            </div>
            <div className="space-y-1 text-center sm:text-left">
              <p className="text-sm font-medium">Profile Photo</p>
              <p className="text-xs text-muted-foreground">
                Click the camera icon to upload a new photo.
                <br />
                Recommended: Square image, at least 400x400px.
              </p>
            </div>
          </div>
        </FileUpload>

        <Separator />

        {/* Personal Information */}
        <div className="space-y-4">
          <h3 className="text-sm font-medium">Personal Information</h3>
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="name">Full Name</Label>
              <Input id="name" defaultValue={defaultValues.name} />
            </div>
            <div className="space-y-2">
              <Label htmlFor="username">Username</Label>
              <div className="flex">
                <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                  @
                </span>
                <Input
                  id="username"
                  className="rounded-l-none"
                  defaultValue={defaultValues.username}
                />
              </div>
            </div>
          </div>
          <div className="space-y-2">
            <Label htmlFor="bio">Bio</Label>
            <Textarea
              id="bio"
              rows={3}
              defaultValue={defaultValues.bio}
              placeholder="Write a short bio about yourself"
            />
          </div>
        </div>

        <Separator />

        {/* Work Information */}
        <div className="space-y-4">
          <h3 className="text-sm font-medium">Work</h3>
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="jobTitle">Job Title</Label>
              <Input id="jobTitle" defaultValue={defaultValues.jobTitle} />
            </div>
            <div className="space-y-2">
              <Label htmlFor="company">Company</Label>
              <Input id="company" defaultValue={defaultValues.company} />
            </div>
          </div>
          <div className="space-y-2">
            <Label htmlFor="location">Location</Label>
            <Input
              id="location"
              defaultValue={defaultValues.location}
              placeholder="City, Country"
            />
          </div>
        </div>

        <Separator />

        {/* Social Links */}
        <div className="space-y-4">
          <h3 className="text-sm font-medium">Social Links</h3>
          <div className="space-y-3">
            <div className="flex items-center gap-3">
              <Globe className="size-5 shrink-0 text-muted-foreground" />
              <Input
                placeholder="https://yourwebsite.com"
                defaultValue={defaultValues.website}
              />
            </div>
            <div className="flex items-center gap-3">
              <Twitter className="size-5 shrink-0 text-muted-foreground" />
              <div className="flex flex-1">
                <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                  x.com/
                </span>
                <Input
                  className="rounded-l-none"
                  placeholder="username"
                  defaultValue={defaultValues.socialLinks?.twitter}
                />
              </div>
            </div>
            <div className="flex items-center gap-3">
              <Linkedin className="size-5 shrink-0 text-muted-foreground" />
              <div className="flex flex-1">
                <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                  linkedin.com/in/
                </span>
                <Input
                  className="rounded-l-none"
                  placeholder="username"
                  defaultValue={defaultValues.socialLinks?.linkedin}
                />
              </div>
            </div>
            <div className="flex items-center gap-3">
              <Github className="size-5 shrink-0 text-muted-foreground" />
              <div className="flex flex-1">
                <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                  github.com/
                </span>
                <Input
                  className="rounded-l-none"
                  placeholder="username"
                  defaultValue={defaultValues.socialLinks?.github}
                />
              </div>
            </div>
          </div>
        </div>

        <div className="flex justify-end gap-2 pt-4">
          <Button variant="primary">Cancel</Button>
          <Button>Save Changes</Button>
        </div>
      </CardContent>
    </Card>
  );
};

export { SettingsProfile2 };

settings-profile-5.source:
"use client";

import { Camera, Github, Globe, Linkedin, MapPin, Twitter } from "lucide-react";
import { useState } from "react";

import { FileUpload, FileUploadTrigger } from "@/components/ui/file-upload";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

interface ProfileData {
  name: string;
  username: string;
  email: string;
  avatar?: string;
  bio?: string;
  role?: string;
  location?: string;
  website?: string;
  twitter?: string;
  linkedin?: string;
  github?: string;
}

interface SettingsProfile5Props {
  defaultValues?: Partial<ProfileData>;
  className?: string;
}

const SettingsProfile5 = ({
  defaultValues = {
    name: "Jordan Chen",
    username: "jordanchen",
    email: "jordan.chen@email.com",
    avatar:
      "https://i.pravatar.cc/150?img=3",
    bio: "Full-stack developer building tools for the modern web. Open source enthusiast and occasional writer about software architecture.",
    role: "Senior Software Engineer",
    location: "Seattle, WA",
    website: "https://jordanchen.dev",
    twitter: "jordanchen",
    linkedin: "jordanchen",
    github: "jordanchen",
  },
  className,
}: SettingsProfile5Props) => {
  const [formData, setFormData] = useState(defaultValues);
  const [avatarFiles, setAvatarFiles] = useState<File[]>([]);

  const updateField = (field: keyof ProfileData, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const avatarPreview =
    avatarFiles.length > 0
      ? URL.createObjectURL(avatarFiles[0])
      : formData.avatar;

  const initials = formData.name
    ?.split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase();

  return (
    <section className={cn("py-16", className)}>
      <div className="container mx-auto">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold">Edit Profile</h1>
          <p className="text-muted-foreground">
            Update your profile information. Changes will be reflected in the
            preview.
          </p>
        </div>

        <div className="grid gap-8 lg:grid-cols-5">
          {/* Edit Form - Takes more space */}
          <div className="space-y-6 lg:col-span-3">
            <Card>
              <CardHeader>
                <CardTitle>Basic Information</CardTitle>
                <CardDescription>
                  Your public profile information
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <FileUpload
                  value={avatarFiles}
                  onValueChange={setAvatarFiles}
                  accept="image/*"
                  maxFiles={1}
                  maxSize={2 * 1024 * 1024}
                >
                  <div className="flex items-center gap-4">
                    <div className="relative">
                      <Avatar className="size-16">
                        <AvatarImage
                          src={avatarPreview}
                          alt={formData.name}
                          className="object-cover"
                        />
                        <AvatarFallback>{initials}</AvatarFallback>
                      </Avatar>
                      <FileUploadTrigger asChild>
                        <Button
                          size="sm"
                          variant="secondary"
                          className="absolute -right-1 -bottom-1 size-6 rounded-full shadow-sm"
                        >
                          <Camera className="size-3" />
                        </Button>
                      </FileUploadTrigger>
                    </div>
                    <div className="space-y-1">
                      <p className="text-sm font-medium">Profile Photo</p>
                      <p className="text-xs text-muted-foreground">
                        JPG, PNG or GIF. Max 2MB.
                      </p>
                    </div>
                  </div>
                </FileUpload>

                <div className="grid gap-4 sm:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="name">Name</Label>
                    <Input
                      id="name"
                      value={formData.name}
                      onChange={(e) => updateField("name", e.target.value)}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="username">Username</Label>
                    <Input
                      id="username"
                      value={formData.username}
                      onChange={(e) => updateField("username", e.target.value)}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="role">Role / Title</Label>
                  <Input
                    id="role"
                    value={formData.role}
                    onChange={(e) => updateField("role", e.target.value)}
                    placeholder="What do you do?"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="bio">Bio</Label>
                  <Textarea
                    id="bio"
                    rows={3}
                    value={formData.bio}
                    onChange={(e) => updateField("bio", e.target.value)}
                    placeholder="Tell others about yourself"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="location">Location</Label>
                  <Input
                    id="location"
                    value={formData.location}
                    onChange={(e) => updateField("location", e.target.value)}
                    placeholder="City, Country"
                  />
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Links</CardTitle>
                <CardDescription>Your website and social links</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="website">Website</Label>
                  <Input
                    id="website"
                    type="url"
                    value={formData.website}
                    onChange={(e) => updateField("website", e.target.value)}
                    placeholder="https://yourwebsite.com"
                  />
                </div>

                <div className="grid gap-4 sm:grid-cols-3">
                  <div className="space-y-2">
                    <Label htmlFor="twitter">Twitter</Label>
                    <Input
                      id="twitter"
                      value={formData.twitter}
                      onChange={(e) => updateField("twitter", e.target.value)}
                      placeholder="username"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="linkedin">LinkedIn</Label>
                    <Input
                      id="linkedin"
                      value={formData.linkedin}
                      onChange={(e) => updateField("linkedin", e.target.value)}
                      placeholder="username"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="github">GitHub</Label>
                    <Input
                      id="github"
                      value={formData.github}
                      onChange={(e) => updateField("github", e.target.value)}
                      placeholder="username"
                    />
                  </div>
                </div>
              </CardContent>
            </Card>

            <div className="flex justify-end gap-3">
              <Button variant="primary">Cancel</Button>
              <Button>Save changes</Button>
            </div>
          </div>

          {/* Live Preview */}
          <div className="lg:col-span-2">
            <div className="sticky top-8">
              <div className="rounded-xl bg-muted/50 p-6">
                <div className="mb-3 flex items-center justify-between">
                  <p className="text-sm font-medium">Live Preview</p>
                  <Badge variant="secondary" className="text-xs">
                    Public view
                  </Badge>
                </div>

                <Card className="!shadow-none">
                  <CardContent className="pt-6">
                    <div className="flex flex-col items-center text-center">
                      <Avatar className="size-20 ring-2 ring-background">
                        <AvatarImage
                          src={avatarPreview}
                          alt={formData.name}
                          className="object-cover"
                        />
                        <AvatarFallback className="text-xl">
                          {initials}
                        </AvatarFallback>
                      </Avatar>

                      <h3 className="mt-4 text-lg font-semibold">
                        {formData.name || "Your Name"}
                      </h3>
                      <p className="text-sm text-muted-foreground">
                        @{formData.username || "username"}
                      </p>

                      {formData.role && (
                        <p className="mt-1 text-sm">{formData.role}</p>
                      )}

                      {formData.location && (
                        <div className="mt-2 flex items-center gap-1 text-sm text-muted-foreground">
                          <MapPin className="size-3.5" />
                          <span>{formData.location}</span>
                        </div>
                      )}

                      {formData.bio && (
                        <>
                          <Separator className="my-4" />
                          <p className="text-sm text-muted-foreground">
                            {formData.bio}
                          </p>
                        </>
                      )}

                      {(formData.website ||
                        formData.twitter ||
                        formData.linkedin ||
                        formData.github) && (
                        <>
                          <Separator className="my-4" />
                          <div className="flex gap-3">
                            {formData.website && (
                              <a
                                href={formData.website}
                                className="text-muted-foreground hover:text-foreground"
                              >
                                <Globe className="size-5" />
                              </a>
                            )}
                            {formData.twitter && (
                              <a
                                href={`https://x.com/${formData.twitter}`}
                                className="text-muted-foreground hover:text-foreground"
                              >
                                <Twitter className="size-5" />
                              </a>
                            )}
                            {formData.linkedin && (
                              <a
                                href={`https://linkedin.com/in/${formData.linkedin}`}
                                className="text-muted-foreground hover:text-foreground"
                              >
                                <Linkedin className="size-5" />
                              </a>
                            )}
                            {formData.github && (
                              <a
                                href={`https://github.com/${formData.github}`}
                                className="text-muted-foreground hover:text-foreground"
                              >
                                <Github className="size-5" />
                              </a>
                            )}
                          </div>
                        </>
                      )}
                    </div>
                  </CardContent>
                </Card>

                <p className="mt-3 text-center text-xs text-muted-foreground">
                  This is how your profile appears to others
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export { SettingsProfile5 };

settings-profile-6.source:
"use client";

import { Check, ChevronLeft, ChevronRight, Upload } from "lucide-react";
import { useState } from "react";

import { FileUpload, FileUploadTrigger } from "@/components/ui/file-upload";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

interface ProfileData {
  name: string;
  username: string;
  avatar?: string;
  bio?: string;
  email?: string;
  phone?: string;
  location?: string;
  website?: string;
  twitter?: string;
  linkedin?: string;
}

interface SettingsProfile6Props {
  defaultValues?: Partial<ProfileData>;
  className?: string;
}

const steps = [
  { id: 1, title: "Basic Info", description: "Name and photo" },
  { id: 2, title: "Contact", description: "How to reach you" },
  { id: 3, title: "Social", description: "Your online presence" },
  { id: 4, title: "Review", description: "Confirm your details" },
];

const SettingsProfile6 = ({
  defaultValues = {
    name: "",
    username: "",
    avatar: "",
    bio: "",
    email: "",
    phone: "",
    location: "",
    website: "",
    twitter: "",
    linkedin: "",
  },
  className,
}: SettingsProfile6Props) => {
  const [currentStep, setCurrentStep] = useState(1);
  const [avatarFiles, setAvatarFiles] = useState<File[]>([]);
  const [formData, setFormData] = useState<ProfileData>({
    name: defaultValues.name || "",
    username: defaultValues.username || "",
    avatar: defaultValues.avatar || "",
    bio: defaultValues.bio || "",
    email: defaultValues.email || "",
    phone: defaultValues.phone || "",
    location: defaultValues.location || "",
    website: defaultValues.website || "",
    twitter: defaultValues.twitter || "",
    linkedin: defaultValues.linkedin || "",
  });

  const updateField = (field: keyof ProfileData, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const nextStep = () => setCurrentStep((prev) => Math.min(prev + 1, 4));
  const prevStep = () => setCurrentStep((prev) => Math.max(prev - 1, 1));

  const avatarPreview =
    avatarFiles.length > 0
      ? URL.createObjectURL(avatarFiles[0])
      : formData.avatar;

  const initials = formData.name
    ?.split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase();

  return (
    <section className={cn("py-16", className)}>
      <div className="container max-w-2xl">
        {/* Header */}
        <div className="mb-8 text-center">
          <h1 className="text-2xl font-semibold">Complete Your Profile</h1>
          <p className="text-muted-foreground">
            Help others get to know you better
          </p>
        </div>

        {/* Progress Steps */}
        <div className="mb-8">
          <div className="flex items-center justify-between">
            {steps.map((step, index) => (
              <div key={step.id} className="flex items-center">
                <div className="flex flex-col items-center">
                  <div
                    className={cn(
                      "flex size-10 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
                      currentStep > step.id
                        ? "border-primary bg-primary text-primary-foreground"
                        : currentStep === step.id
                          ? "border-primary text-primary"
                          : "border-muted text-muted-foreground",
                    )}
                  >
                    {currentStep > step.id ? (
                      <Check className="size-5" />
                    ) : (
                      step.id
                    )}
                  </div>
                  <div className="mt-2 text-center">
                    <p
                      className={cn(
                        "text-sm font-medium",
                        currentStep >= step.id
                          ? "text-foreground"
                          : "text-muted-foreground",
                      )}
                    >
                      {step.title}
                    </p>
                    <p className="hidden text-xs text-muted-foreground sm:block">
                      {step.description}
                    </p>
                  </div>
                </div>
                {index < steps.length - 1 && (
                  <div
                    className={cn(
                      "mx-2 h-0.5 w-12 sm:w-20",
                      currentStep > step.id ? "bg-primary" : "bg-muted",
                    )}
                  />
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Step Content */}
        <Card>
          <CardContent className="p-6">
            {/* Step 1: Basic Info */}
            {currentStep === 1 && (
              <div className="space-y-6">
                <FileUpload
                  value={avatarFiles}
                  onValueChange={setAvatarFiles}
                  accept="image/*"
                  maxFiles={1}
                  maxSize={2 * 1024 * 1024}
                >
                  <div className="flex flex-col items-center gap-4">
                    <Avatar className="size-24">
                      <AvatarImage
                        src={avatarPreview}
                        alt={formData.name}
                        className="object-cover"
                      />
                      <AvatarFallback className="text-2xl">
                        {initials || "?"}
                      </AvatarFallback>
                    </Avatar>
                    <FileUploadTrigger asChild>
                      <Button variant="primary" size="sm">
                        <Upload className="mr-2 size-4" />
                        Upload photo
                      </Button>
                    </FileUploadTrigger>
                  </div>
                </FileUpload>

                <div className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="name">Full name *</Label>
                    <Input
                      id="name"
                      value={formData.name}
                      onChange={(e) => updateField("name", e.target.value)}
                      placeholder="Enter your full name"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="username">Username *</Label>
                    <div className="flex">
                      <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                        @
                      </span>
                      <Input
                        id="username"
                        className="rounded-l-none"
                        value={formData.username}
                        onChange={(e) =>
                          updateField("username", e.target.value)
                        }
                        placeholder="Choose a username"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="bio">Bio</Label>
                    <Textarea
                      id="bio"
                      rows={3}
                      value={formData.bio}
                      onChange={(e) => updateField("bio", e.target.value)}
                      placeholder="Tell us a bit about yourself"
                    />
                  </div>
                </div>
              </div>
            )}

            {/* Step 2: Contact */}
            {currentStep === 2 && (
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="email">Email address *</Label>
                  <Input
                    id="email"
                    type="email"
                    value={formData.email}
                    onChange={(e) => updateField("email", e.target.value)}
                    placeholder="you@example.com"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="phone">Phone number</Label>
                  <Input
                    id="phone"
                    type="tel"
                    value={formData.phone}
                    onChange={(e) => updateField("phone", e.target.value)}
                    placeholder="+1 (555) 000-0000"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="location">Location</Label>
                  <Input
                    id="location"
                    value={formData.location}
                    onChange={(e) => updateField("location", e.target.value)}
                    placeholder="City, Country"
                  />
                </div>
              </div>
            )}

            {/* Step 3: Social */}
            {currentStep === 3 && (
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="website">Personal website</Label>
                  <Input
                    id="website"
                    type="url"
                    value={formData.website}
                    onChange={(e) => updateField("website", e.target.value)}
                    placeholder="https://yourwebsite.com"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="twitter">Twitter / X</Label>
                  <div className="flex">
                    <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                      x.com/
                    </span>
                    <Input
                      id="twitter"
                      className="rounded-l-none"
                      value={formData.twitter}
                      onChange={(e) => updateField("twitter", e.target.value)}
                      placeholder="username"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="linkedin">LinkedIn</Label>
                  <div className="flex">
                    <span className="inline-flex items-center rounded-l-md border border-r-0 bg-muted px-3 text-sm text-muted-foreground">
                      linkedin.com/in/
                    </span>
                    <Input
                      id="linkedin"
                      className="rounded-l-none"
                      value={formData.linkedin}
                      onChange={(e) => updateField("linkedin", e.target.value)}
                      placeholder="username"
                    />
                  </div>
                </div>
              </div>
            )}

            {/* Step 4: Review */}
            {currentStep === 4 && (
              <div className="space-y-6">
                <div className="flex items-center gap-4">
                  <Avatar className="size-16">
                    <AvatarImage
                      src={avatarPreview}
                      alt={formData.name}
                      className="object-cover"
                    />
                    <AvatarFallback>{initials || "?"}</AvatarFallback>
                  </Avatar>
                  <div>
                    <h3 className="font-semibold">
                      {formData.name || "No name set"}
                    </h3>
                    <p className="text-sm text-muted-foreground">
                      @{formData.username || "username"}
                    </p>
                  </div>
                </div>

                {formData.bio && (
                  <p className="text-sm text-muted-foreground">
                    {formData.bio}
                  </p>
                )}

                <div className="grid gap-4 rounded-lg border p-4 sm:grid-cols-2">
                  <div>
                    <p className="text-xs font-medium text-muted-foreground">
                      Email
                    </p>
                    <p className="text-sm">{formData.email || "Not set"}</p>
                  </div>
                  <div>
                    <p className="text-xs font-medium text-muted-foreground">
                      Phone
                    </p>
                    <p className="text-sm">{formData.phone || "Not set"}</p>
                  </div>
                  <div>
                    <p className="text-xs font-medium text-muted-foreground">
                      Location
                    </p>
                    <p className="text-sm">{formData.location || "Not set"}</p>
                  </div>
                  <div>
                    <p className="text-xs font-medium text-muted-foreground">
                      Website
                    </p>
                    <p className="text-sm">{formData.website || "Not set"}</p>
                  </div>
                </div>

                <div className="rounded-lg bg-muted/50 p-4">
                  <p className="text-sm text-muted-foreground">
                    Please review your information above. Click &quot;Complete
                    Setup&quot; to save your profile, or go back to make
                    changes.
                  </p>
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Navigation */}
        <div className="mt-6 flex items-center justify-between">
          <Button
            variant="primary"
            onClick={prevStep}
            disabled={currentStep === 1}
          >
            <ChevronLeft className="mr-2 size-4" />
            Back
          </Button>

          {currentStep < 4 ? (
            <Button onClick={nextStep}>
              Continue
              <ChevronRight className="ml-2 size-4" />
            </Button>
          ) : (
            <Button>
              <Check className="mr-2 size-4" />
              Complete Setup
            </Button>
          )}
        </div>

        {/* Skip option */}
        {currentStep < 4 && (
          <p className="mt-4 text-center text-sm text-muted-foreground">
            <button
              onClick={() => setCurrentStep(4)}
              className="underline hover:text-foreground"
            >
              Skip to review
            </button>
          </p>
        )}
      </div>
    </section>
  );
};

export { SettingsProfile6 };

settings-profile-7.source:
"use client";

import { Camera, Check, Pencil, X } from "lucide-react";
import { useState } from "react";

import { FileUpload, FileUploadTrigger } from "@/components/ui/file-upload";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

interface ProfileData {
  name: string;
  email: string;
  avatar?: string;
  role?: string;
  location?: string;
}

interface SettingsProfile7Props {
  defaultValues?: Partial<ProfileData>;
  className?: string;
}

const SettingsProfile7 = ({
  defaultValues = {
    name: "Alex Morgan",
    email: "alex.morgan@email.com",
    avatar:
      "https://i.pravatar.cc/150?img=8",
    role: "Product Designer",
    location: "San Francisco, CA",
  },
  className,
}: SettingsProfile7Props) => {
  const [editingField, setEditingField] = useState<string | null>(null);
  const [formData, setFormData] = useState(defaultValues);
  const [tempValue, setTempValue] = useState("");
  const [avatarFiles, setAvatarFiles] = useState<File[]>([]);

  const avatarPreview =
    avatarFiles.length > 0
      ? URL.createObjectURL(avatarFiles[0])
      : formData.avatar;

  const startEdit = (field: string, currentValue: string) => {
    setEditingField(field);
    setTempValue(currentValue);
  };

  const saveEdit = (field: keyof ProfileData) => {
    setFormData((prev) => ({ ...prev, [field]: tempValue }));
    setEditingField(null);
  };

  const cancelEdit = () => {
    setEditingField(null);
    setTempValue("");
  };

  const initials = formData.name
    ?.split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase();

  const EditableField = ({
    field,
    label,
    value,
  }: {
    field: keyof ProfileData;
    label: string;
    value?: string;
  }) => {
    const isEditing = editingField === field;

    return (
      <div className="group/field relative flex items-center py-2">
        {/* Reserve space so the value never sits under the edit control; hover/focus applies to this whole block */}
        <div className="relative min-w-0 flex-1 pr-10">
          <p className="text-xs text-muted-foreground">{label}</p>
          {isEditing ? (
            <div className="mt-1 flex items-center gap-2">
              <Input
                value={tempValue}
                onChange={(e) => setTempValue(e.target.value)}
                className="h-8"
                autoFocus
                onKeyDown={(e) => {
                  if (e.key === "Enter") saveEdit(field);
                  if (e.key === "Escape") cancelEdit();
                }}
              />
              <Button
                size="sm"
                variant="ghost"
                className="size-8 shrink-0"
                onClick={() => saveEdit(field)}
              >
                <Check className="size-4 text-green-600" />
              </Button>
              <Button
                size="sm"
                variant="ghost"
                className="size-8 shrink-0"
                onClick={cancelEdit}
              >
                <X className="size-4 text-muted-foreground" />
              </Button>
            </div>
          ) : (
            <p className="truncate text-sm font-medium">
              {value || <span className="text-muted-foreground">Not set</span>}
            </p>
          )}
          {!isEditing && (
            <Button
              type="button"
              size="sm"
              variant="ghost"
              aria-label={`Edit ${label}`}
              className={cn(
                "absolute top-1/2 right-0 size-8 -translate-y-1/2 shrink-0 transition-opacity",
                "opacity-0 pointer-events-none",
                "group-hover/field:opacity-100 group-hover/field:pointer-events-auto",
                "group-focus-within/field:opacity-100 group-focus-within/field:pointer-events-auto",
                "focus-visible:opacity-100 focus-visible:pointer-events-auto",
              )}
              onClick={() => startEdit(field, value || "")}
            >
              <Pencil className="size-3.5" />
            </Button>
          )}
        </div>
      </div>
    );
  };

  return (
    <Card className={cn("w-full max-w-md", className)}>
      <CardContent className="p-4">
        <div className="flex gap-4">
          {/* Avatar */}
          <FileUpload
            value={avatarFiles}
            onValueChange={setAvatarFiles}
            accept="image/*"
            maxFiles={1}
            maxSize={2 * 1024 * 1024}
          >
            <div className="relative shrink-0">
              <Avatar className="size-16">
                <AvatarImage alt={formData.name} className="object-cover" />
                <AvatarFallback>{initials}</AvatarFallback>
              </Avatar>
              <FileUploadTrigger asChild>
                <Button
                  size="sm"
                  variant="secondary"
                  className="absolute -right-1 -bottom-1 size-6 rounded-full shadow-sm"
                >
                  <Camera className="size-3" />
                </Button>
              </FileUploadTrigger>
            </div>
          </FileUpload>

          {/* Editable Fields */}
          <div className="min-w-0 flex-1 divide-y">
            <EditableField field="name" label="Name" value={formData.name} />
            <EditableField field="role" label="Role" value={formData.role} />
            <EditableField field="email" label="Email" value={formData.email} />
            <EditableField
              field="location"
              label="Location"
              value={formData.location}
            />
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

export { SettingsProfile7 };

